//-------------------------------------------------------------------------
// 거래처 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_clntNo_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_clntNo.setValue(rtnList[0]);	// 코드값
			ed_clntNm.setValue(rtnList[1]);	// 코드명
		} else {
			ed_clntNo.setValue("");
			ed_clntNm.setValue("");
		}

    } catch (e) {
       console.log(e);
    }
};

